import{_ as a,c as t,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse(`{"title":"Platform Features: Models & Quota | opencode-antigravity-auth","description":"Learn about Antigravity Auth's platform features including available models, dual quota system, Google Search grounding, and Thinking models configuration.","frontmatter":{"title":"Platform Features: Models & Quota | opencode-antigravity-auth","sidebarTitle":"Platform Features","subtitle":"Platform Features: Models & Quota","description":"Learn about Antigravity Auth's platform features including available models, dual quota system, Google Search grounding, and Thinking models configuration.","order":2},"headers":[],"relativePath":"NoeFabris/opencode-antigravity-auth/platforms/index.md","filePath":"NoeFabris/opencode-antigravity-auth/platforms/index.md"}`),l={name:"NoeFabris/opencode-antigravity-auth/platforms/index.md"};function n(r,e,s,u,d,h){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="platform-features" tabindex="-1">Platform Features <a class="header-anchor" href="#platform-features" aria-label="Permalink to &quot;Platform Features&quot;">​</a></h1><p>This section helps you gain a deep understanding of the models, quota system, and platform features supported by the Antigravity Auth plugin. You&#39;ll learn how to select the right model, configure Thinking capabilities, enable Google Search, and maximize quota utilization.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Before You Begin</p><p>Before proceeding with this section, ensure you have completed:</p><ul><li><a href="./../start/quick-install/">Quick Installation</a>: Complete plugin installation and initial authentication</li><li><a href="./../start/first-request/">First Request</a>: Successfully send your first model request</li></ul></div><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to &quot;Learning Path&quot;">​</a></h2><p>Follow this sequence to progressively master platform features:</p><h3 id="_1-available-models" tabindex="-1">1. <a href="./available-models/">Available Models</a> <a class="header-anchor" href="#_1-available-models" aria-label="Permalink to &quot;1. [Available Models](./available-models/)&quot;">​</a></h3><p>Learn about all available models and their variant configurations.</p><ul><li>Get to know Claude Opus 4.5, Sonnet 4.5, and Gemini 3 Pro/Flash</li><li>Understand the model distribution across Antigravity and Gemini CLI quota pools</li><li>Master the use of the <code>--variant</code> parameter</li></ul><h3 id="_2-dual-quota-system" tabindex="-1">2. <a href="./dual-quota-system/">Dual Quota System</a> <a class="header-anchor" href="#_2-dual-quota-system" aria-label="Permalink to &quot;2. [Dual Quota System](./dual-quota-system/)&quot;">​</a></h3><p>Understand how the Antigravity and Gemini CLI dual quota pools work.</p><ul><li>Learn how each account has two independent Gemini quota pools</li><li>Enable automatic fallback configuration to double your quota</li><li>Explicitly specify models to use specific quota pools</li></ul><h3 id="_3-google-search-grounding" tabindex="-1">3. <a href="./google-search-grounding/">Google Search Grounding</a> <a class="header-anchor" href="#_3-google-search-grounding" aria-label="Permalink to &quot;3. [Google Search Grounding](./google-search-grounding/)&quot;">​</a></h3><p>Enable Google Search for Gemini models to improve factual accuracy.</p><ul><li>Allow Gemini to search real-time web information</li><li>Adjust search thresholds to control search frequency</li><li>Choose appropriate configurations based on task requirements</li></ul><h3 id="_4-thinking-models" tabindex="-1">4. <a href="./thinking-models/">Thinking Models</a> <a class="header-anchor" href="#_4-thinking-models" aria-label="Permalink to &quot;4. [Thinking Models](./thinking-models/)&quot;">​</a></h3><p>Master the configuration and usage of Claude and Gemini 3 Thinking models.</p><ul><li>Configure Claude&#39;s thinking budget</li><li>Use Gemini 3&#39;s thinking level (minimal/low/medium/high)</li><li>Understand interleaved thinking and thinking block retention strategies</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this section, you can continue learning:</p><ul><li><a href="./../advanced/multi-account-setup/">Multi-Account Setup</a>: Configure multiple Google accounts to implement quota pooling and load balancing</li><li><a href="./../advanced/account-selection-strategies/">Account Selection Strategies</a>: Master best practices for sticky, round-robin, and hybrid strategies</li><li><a href="./../advanced/configuration-guide/">Configuration Guide</a>: Master all configuration options and customize plugin behavior as needed</li></ul>',21)])])}const m=a(l,[["render",n]]);export{g as __pageData,m as default};
